/**
 * Tests for Notification Service
 */

import * as Notifications from "expo-notifications";
import { notificationService } from "../../services/notificationService";

// Mock expo-notifications
jest.mock("expo-notifications", () => ({
  setNotificationHandler: jest.fn(),
  setNotificationChannelAsync: jest.fn(),
  getPermissionsAsync: jest.fn(),
  requestPermissionsAsync: jest.fn(),
  scheduleNotificationAsync: jest.fn(),
  cancelAllScheduledNotificationsAsync: jest.fn(),
  getBadgeCountAsync: jest.fn(),
  setBadgeCountAsync: jest.fn(),
  AndroidImportance: { MAX: 5 },
  AndroidNotificationPriority: { HIGH: "high" },
}));

// Mock Platform
jest.mock("react-native", () => ({
  Platform: { OS: "android" },
}));

describe("notificationService", () => {
  beforeEach(() => {
    jest.clearAllMocks();
    (Notifications.getPermissionsAsync as jest.Mock).mockResolvedValue({
      status: "granted",
    });
    (Notifications.requestPermissionsAsync as jest.Mock).mockResolvedValue({
      status: "granted",
    });
    (Notifications.scheduleNotificationAsync as jest.Mock).mockResolvedValue(
      "notif-123",
    );
  });

  describe("requestPermissions", () => {
    it("should request notification permissions", async () => {
      const result = await notificationService.requestPermissions();

      expect(Notifications.getPermissionsAsync).toHaveBeenCalled();
      expect(result).toBe(true);
    });

    it("should return false if permission denied", async () => {
      (Notifications.getPermissionsAsync as jest.Mock).mockResolvedValue({
        status: "denied",
      });
      (Notifications.requestPermissionsAsync as jest.Mock).mockResolvedValue({
        status: "denied",
      });

      const result = await notificationService.requestPermissions();

      expect(result).toBe(false);
    });
  });

  describe("scheduleAINotification", () => {
    it("should schedule an AI notification", async () => {
      const result = await notificationService.scheduleAINotification({
        type: "analysis_complete",
        title: "Test Title",
        body: "Test Body",
        projectId: 1,
        projectName: "Test Project",
      });

      expect(Notifications.scheduleNotificationAsync).toHaveBeenCalledWith({
        content: expect.objectContaining({
          title: "Test Title",
          body: "Test Body",
        }),
        trigger: null,
      });
      expect(result).toBe("notif-123");
    });

    it("should return empty string if no permission", async () => {
      (Notifications.getPermissionsAsync as jest.Mock).mockResolvedValue({
        status: "denied",
      });
      (Notifications.requestPermissionsAsync as jest.Mock).mockResolvedValue({
        status: "denied",
      });

      const result = await notificationService.scheduleAINotification({
        type: "chat_response",
        title: "Test",
        body: "Test",
      });

      expect(result).toBe("");
    });
  });

  describe("notifyAnalysisComplete", () => {
    it("should notify when analysis is complete", async () => {
      const result = await notificationService.notifyAnalysisComplete(
        "Villa Project",
        85,
        123,
      );

      expect(Notifications.scheduleNotificationAsync).toHaveBeenCalledWith(
        expect.objectContaining({
          content: expect.objectContaining({
            title: "📸 Phân tích ảnh hoàn tất",
            body: expect.stringContaining("Villa Project"),
          }),
        }),
      );
    });
  });

  describe("notifyReportReady", () => {
    it("should notify when report is ready", async () => {
      const result = await notificationService.notifyReportReady(
        "Monthly Report",
        456,
      );

      expect(Notifications.scheduleNotificationAsync).toHaveBeenCalledWith(
        expect.objectContaining({
          content: expect.objectContaining({
            title: "📊 Báo cáo đã sẵn sàng",
          }),
        }),
      );
    });
  });
});
